import { useState, useCallback } from 'react';
import styles from './CRUDPage.module.css';

const MOCK_ITEMS = [
  { id: 1, name: 'Adam Novák',     email: 'adam@example.com',  role: 'admin'  },
  { id: 2, name: 'Barbora Dvořák', email: 'bara@example.com',  role: 'editor' },
  { id: 3, name: 'Czech Kovář',    email: 'czech@example.com', role: 'viewer' },
  { id: 4, name: 'Dana Procházka', email: 'dana@example.com',  role: 'editor' },
];

let nextId = MOCK_ITEMS.length + 1;

function Dialog({ open, onClose, title, children }) {
  if (!open) return null;
  return (
    <div className={styles.overlay} onClick={e => e.target === e.currentTarget && onClose()}>
      <div className={styles.dialog}>
        <div className={styles.dialogHeader}>
          <span className={styles.dialogTitle}>{title}</span>
          <button className={styles.dialogClose} onClick={onClose}>✕</button>
        </div>
        <div className={styles.dialogBody}>{children}</div>
      </div>
    </div>
  );
}

function ItemForm({ initial = {}, onSave, onCancel }) {
  const [form, setForm] = useState({ name: '', email: '', role: 'viewer', ...initial });
  const set = k => e => setForm(p => ({ ...p, [k]: e.target.value }));

  return (
    <form className={styles.form} onSubmit={e => { e.preventDefault(); onSave(form); }}>
      <label className={styles.formLabel}>
        Jméno
        <input className={styles.formInput} value={form.name} onChange={set('name')} placeholder="Jan Novák" required />
      </label>
      <label className={styles.formLabel}>
        E-mail
        <input className={styles.formInput} type="email" value={form.email} onChange={set('email')} placeholder="jan@example.com" required />
      </label>
      <label className={styles.formLabel}>
        Role
        <select className={styles.formInput} value={form.role} onChange={set('role')}>
          <option value="viewer">Viewer</option>
          <option value="editor">Editor</option>
          <option value="admin">Admin</option>
        </select>
      </label>
      <div className={styles.formActions}>
        <button type="button" className={styles.btnSecondary} onClick={onCancel}>Zrušit</button>
        <button type="submit" className={styles.btnPrimary}>{initial.id ? 'Uložit změny' : 'Vytvořit'}</button>
      </div>
    </form>
  );
}

export function CRUDPage() {
  const [items,   setItems]   = useState(MOCK_ITEMS);
  const [search,  setSearch]  = useState('');
  const [dialog,  setDialog]  = useState(null);

  const filtered = items.filter(i =>
    i.name.toLowerCase().includes(search.toLowerCase()) ||
    i.email.toLowerCase().includes(search.toLowerCase())
  );

  const handleCreate = useCallback(form => {
    setItems(p => [...p, { ...form, id: nextId++ }]);
    setDialog(null);
  }, []);

  const handleUpdate = useCallback(form => {
    setItems(p => p.map(i => i.id === dialog.id ? { ...i, ...form } : i));
    setDialog(null);
  }, [dialog]);

  const handleDelete = useCallback(id => {
    setItems(p => p.filter(i => i.id !== id));
  }, []);

  const ROLE_CLS = { admin: styles.roleAdmin, editor: styles.roleEditor, viewer: styles.roleViewer };

  return (
    <div className={styles.page}>
      <div className={styles.pageHeader}>
        <div>
          <h1 className={styles.pageTitle}>Uživatelé</h1>
          <p className={styles.pageSub}>{items.length} záznamů celkem</p>
        </div>
        <div className={styles.headerActions}>
          <div className={styles.searchWrap}>
            <svg className={styles.searchIcon} width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><circle cx="11" cy="11" r="8"/><path d="m21 21-4.35-4.35"/></svg>
            <input className={styles.search} placeholder="Hledat..." value={search} onChange={e => setSearch(e.target.value)} />
          </div>
          <button className={styles.btnPrimary} onClick={() => setDialog('create')}>+ Přidat</button>
        </div>
      </div>

      <div className={styles.tableWrap}>
        <table className={styles.table}>
          <thead>
            <tr>
              <th className={styles.th}>Jméno</th>
              <th className={styles.th}>E-mail</th>
              <th className={styles.th}>Role</th>
              <th className={styles.th}></th>
            </tr>
          </thead>
          <tbody>
            {filtered.map(item => (
              <tr key={item.id} className={styles.row}>
                <td className={styles.td}><span className={styles.name}>{item.name}</span></td>
                <td className={styles.td}><span className={styles.email}>{item.email}</span></td>
                <td className={styles.td}>
                  <span className={`${styles.badge} ${ROLE_CLS[item.role] || ''}`}>{item.role}</span>
                </td>
                <td className={styles.tdActions}>
                  <button className={styles.btnEdit} onClick={() => setDialog(item)}>Upravit</button>
                  <button className={styles.btnDelete} onClick={() => handleDelete(item.id)}>Smazat</button>
                </td>
              </tr>
            ))}
            {filtered.length === 0 && (
              <tr><td colSpan={4} className={styles.empty}>Žádné záznamy</td></tr>
            )}
          </tbody>
        </table>
      </div>

      <Dialog open={dialog === 'create'} onClose={() => setDialog(null)} title="Nový uživatel">
        <ItemForm onSave={handleCreate} onCancel={() => setDialog(null)} />
      </Dialog>

      <Dialog open={!!dialog && dialog !== 'create'} onClose={() => setDialog(null)} title="Upravit uživatele">
        <ItemForm initial={dialog || {}} onSave={handleUpdate} onCancel={() => setDialog(null)} />
      </Dialog>
    </div>
  );
}

.page {
  padding: 32px;
  max-width: 860px;
  margin: 0 auto;
  font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', system-ui, sans-serif;
  min-height: 100vh;
  background: #f9f9fb;
}

/* ── Header ── */
.pageHeader {
  display: flex;
  align-items: flex-start;
  justify-content: space-between;
  margin-bottom: 20px;
  gap: 12px;
  flex-wrap: wrap;
}
.pageTitle { margin: 0; font-size: 20px; font-weight: 700; color: #18181b; letter-spacing: -0.02em; }
.pageSub   { margin: 2px 0 0; font-size: 12.5px; color: #71717a; }
.headerActions { display: flex; gap: 8px; align-items: center; }

/* ── Search ── */
.searchWrap { position: relative; }
.searchIcon { position: absolute; left: 9px; top: 50%; transform: translateY(-50%); color: #b4b4bb; pointer-events: none; }
.search {
  padding: 7px 10px 7px 28px;
  border: 1px solid #e4e4e7;
  border-radius: 7px;
  font-size: 13px;
  color: #18181b;
  background: #fff;
  outline: none;
  min-width: 200px;
  transition: border-color 0.12s;
}
.search:focus { border-color: #6366f1; }
.search::placeholder { color: #b4b4bb; }

/* ── Buttons ── */
.btnPrimary {
  padding: 8px 16px;
  background: #6366f1;
  color: #fff;
  font-size: 13px;
  font-weight: 600;
  border: none;
  border-radius: 7px;
  cursor: pointer;
  transition: opacity 0.1s;
  white-space: nowrap;
}
.btnPrimary:hover { opacity: 0.88; }

.btnSecondary {
  padding: 7px 14px;
  font-size: 13px;
  border: 1px solid #e4e4e7;
  border-radius: 7px;
  background: transparent;
  color: #3f3f46;
  cursor: pointer;
}
.btnSecondary:hover { background: #f4f4f5; }

.btnEdit   { font-size: 12.5px; color: #6366f1; background: none; border: none; cursor: pointer; padding: 2px 6px; border-radius: 4px; }
.btnEdit:hover { background: rgba(99,102,241,0.08); }
.btnDelete { font-size: 12.5px; color: #dc2626; background: none; border: none; cursor: pointer; padding: 2px 6px; border-radius: 4px; }
.btnDelete:hover { background: #fef2f2; }

/* ── Table ── */
.tableWrap { background: #fff; border: 1px solid #e4e4e7; border-radius: 10px; overflow: hidden; }
.table { width: 100%; border-collapse: collapse; font-size: 13px; }

.th {
  padding: 10px 14px;
  background: #f9f9fb;
  text-align: left;
  font-size: 11.5px;
  font-weight: 600;
  color: #71717a;
  letter-spacing: 0.04em;
  text-transform: uppercase;
  border-bottom: 1px solid #e4e4e7;
}

.row { transition: background 0.08s; }
.row:hover { background: #f9f9fb; }

.td, .tdActions {
  padding: 11px 14px;
  border-bottom: 1px solid #f2f2f4;
  vertical-align: middle;
}
.table tbody tr:last-child .td,
.table tbody tr:last-child .tdActions { border-bottom: none; }

.tdActions { display: flex; gap: 4px; align-items: center; justify-content: flex-end; }

.name  { font-weight: 500; color: #18181b; }
.email { color: #71717a; font-size: 12.5px; }

.badge { display: inline-flex; padding: 2px 8px; border-radius: 99px; font-size: 11.5px; font-weight: 600; border: 1px solid transparent; }
.roleAdmin  { color: #6366f1; background: rgba(99,102,241,0.08);  border-color: rgba(99,102,241,0.2); }
.roleEditor { color: #0891b2; background: rgba(8,145,178,0.08);   border-color: rgba(8,145,178,0.2);  }
.roleViewer { color: #71717a; background: #f4f4f5;                border-color: #e4e4e7;               }

.empty { text-align: center; color: #b4b4bb; padding: 40px 0; font-size: 13px; }

/* ── Dialog ── */
.overlay {
  position: fixed;
  inset: 0;
  background: rgba(0,0,0,0.35);
  backdrop-filter: blur(2px);
  display: flex;
  align-items: center;
  justify-content: center;
  z-index: 500;
  padding: 16px;
}

.dialog {
  background: #fff;
  border: 1px solid #e4e4e7;
  border-radius: 12px;
  width: 100%;
  max-width: 400px;
  box-shadow: 0 20px 50px rgba(0,0,0,0.12);
}

.dialogHeader {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 16px 18px 12px;
  border-bottom: 1px solid #e4e4e7;
}
.dialogTitle { font-size: 14px; font-weight: 700; color: #18181b; }
.dialogClose { background: none; border: none; color: #71717a; cursor: pointer; font-size: 14px; padding: 2px 6px; border-radius: 4px; }
.dialogClose:hover { background: #f4f4f5; color: #18181b; }
.dialogBody { padding: 18px; }

/* ── Form ── */
.form { display: flex; flex-direction: column; gap: 14px; }
.formLabel { display: flex; flex-direction: column; gap: 5px; font-size: 12.5px; font-weight: 500; color: #3f3f46; }
.formInput {
  padding: 8px 11px;
  border: 1px solid #e4e4e7;
  border-radius: 7px;
  font-size: 13px;
  color: #18181b;
  background: #fff;
  outline: none;
  font-family: inherit;
  transition: border-color 0.12s;
}
.formInput:focus { border-color: #6366f1; }
.formActions { display: flex; justify-content: flex-end; gap: 8px; margin-top: 4px; }

import { useState, useCallback } from 'react';

export function useModal(defaultOpen = false) {
  const [open, setOpen]   = useState(defaultOpen);
  const [data, setData]   = useState(null);

  const openModal  = useCallback((payload = null) => { setData(payload); setOpen(true);  }, []);
  const closeModal = useCallback(() => { setOpen(false); setData(null); }, []);
  const toggle     = useCallback(() => setOpen(v => !v), []);

  return { open, data, openModal, closeModal, toggle };
}

