import { useState, useEffect, useCallback } from 'react';

// Produkční CRUD hook — nahraď endpoint dle projektu
export function useCRUD(endpoint) {
  const [items,   setItems]   = useState([]);
  const [loading, setLoading] = useState(false);
  const [error,   setError]   = useState(null);

  const req = async (method, path, body) => {
    const res = await fetch(`${endpoint}${path}`, {
      method,
      headers: { 'Content-Type': 'application/json', Authorization: `Bearer ${localStorage.getItem('token')}` },
      body: body ? JSON.stringify(body) : undefined,
    });
    if (!res.ok) throw new Error((await res.json()).message || 'Chyba');
    return method === 'DELETE' ? null : res.json();
  };

  useEffect(() => {
    setLoading(true);
    req('GET', '').then(setItems).catch(e => setError(e.message)).finally(() => setLoading(false));
  }, [endpoint]);

  const create = useCallback(async (data) => {
    try {
      setLoading(true);
      const item = await req('POST', '', data);
      setItems(p => [item, ...p]);
      return true;
    } catch (e) { setError(e.message); return false; }
    finally { setLoading(false); }
  }, [endpoint]);

  const update = useCallback(async (id, data) => {
    const prev = items.find(i => i.id === id);
    setItems(p => p.map(i => i.id === id ? { ...i, ...data } : i));
    try {
      const item = await req('PUT', `/${id}`, data);
      setItems(p => p.map(i => i.id === id ? item : i));
      return true;
    } catch (e) {
      setItems(p => p.map(i => i.id === id ? prev : i));
      setError(e.message);
      return false;
    }
  }, [endpoint, items]);

  const remove = useCallback(async (id) => {
    const prev = items;
    setItems(p => p.filter(i => i.id !== id));
    try { await req('DELETE', `/${id}`); return true; }
    catch (e) { setItems(prev); setError(e.message); return false; }
  }, [endpoint, items]);

  return { items, loading, error, create, update, remove };
}
